const input = $input.first().json;

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.openclaw&select=cred_key,cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0) {
  return [{ json: { error: 'OpenClaw credentials not configured. Use add_credential to set them up.' } }];
}

const baseUrl = (creds.find(c => c.cred_key === 'openclaw_url')?.cred_value || '').replace(/\/$/, '');
const apiKey = creds.find(c => c.cred_key === 'openclaw_api_key')?.cred_value;

if (!baseUrl || !apiKey) {
  return [{ json: { error: 'OpenClaw URL and API key are both required. Use add_credential to configure them.' } }];
}

const message = input.message;
if (!message) {
  return [{ json: { error: 'Parameter "message" is required.' } }];
}

try {
  const body = {
    message: message,
    user_id: (input.user_id && input.user_id !== '') ? input.user_id : 'openclaw-bridge',
    session_id: (input.session_id && input.session_id !== '') ? input.session_id : 'openclaw-' + Date.now(),
    source: (input.source && input.source !== '') ? input.source : 'openclaw'
  };

  if (input.metadata && input.metadata !== '') {
    try {
      body.metadata = typeof input.metadata === 'string' ? JSON.parse(input.metadata) : input.metadata;
    } catch (e) {
      return [{ json: { error: 'Invalid JSON in metadata parameter: ' + e.message } }];
    }
  } else {
    body.metadata = {};
  }

  const resp = await helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/webhook/agent',
    headers: {
      'X-API-Key': apiKey,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(body),
    timeout: 120000
  });

  const parsed = typeof resp === 'string' ? JSON.parse(resp) : resp;

  if (parsed.success === false) {
    return [{ json: { error: 'Remote agent returned error: ' + (parsed.error || parsed.response || 'Unknown error') } }];
  }

  let result = '**Response from remote OpenClaw agent:**\n\n' + (parsed.response || '(empty response)');
  if (parsed.session_id) result += '\n\nSession ID: ' + parsed.session_id;

  return [{ json: { result } }];
} catch (err) {
  return [{ json: { error: 'Failed to reach remote OpenClaw instance: ' + err.message } }];
}
